import json

def pretty_print_json(json_string):
    """
    Verilen JSON string'ini parse eder ve okunaklı bir formatta (pretty print) döndürür.
    Geçersiz JSON string'i durumunda hata mesajı döndürür.
    """
    try:
        parsed_data = json.loads(json_string)
        return json.dumps(parsed_data, indent=4, ensure_ascii=False)
    except json.JSONDecodeError as e:
        return f"Hata: Geçersiz JSON stringi. {e}"
